// src/components/ParticlesBg.jsx
import { useEffect, useRef } from 'react';

export default function ParticlesBg() {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    let animId;

    let width = canvas.offsetWidth;
    let height = canvas.offsetHeight;

    const resize = () => {
      width = canvas.parentElement.offsetWidth;
      height = canvas.parentElement.offsetHeight;
      canvas.width = width;
      canvas.height = height;
    };
    resize();

    const ro = new ResizeObserver(resize);
    if (canvas.parentElement) ro.observe(canvas.parentElement);

    // Rastreador del ratón con suavizado (Lerp)
    let mouse = { x: width / 2, y: height / 2, targetX: width / 2, targetY: height / 2 };

    const onMove = (e) => {
      const rect = canvas.getBoundingClientRect();
      mouse.targetX = e.clientX - rect.left;
      mouse.targetY = e.clientY - rect.top;
    };
    
    // Escuchamos el movimiento en toda la sección, no solo en el canvas
    if (canvas.parentElement) {
      canvas.parentElement.addEventListener('mousemove', onMove);
    }

    // 1. Nubes gigantes que forman la Nebulosa (se mueven muy lento)
    const orbs = [
      { x: width * 0.2, y: height * 0.2, vx: 0.3, vy: 0.2, r: Math.max(width * 0.4, 400), color: 'rgba(232, 58, 58, 0.05)' },
      { x: width * 0.8, y: height * 0.8, vx: -0.2, vy: -0.3, r: Math.max(width * 0.3, 300), color: 'rgba(255, 96, 96, 0.04)' },
      { x: width * 0.5, y: height * 0.5, vx: 0.15, vy: -0.1, r: Math.max(width * 0.5, 500), color: 'rgba(200, 20, 20, 0.03)' }
    ];

    // 2. Pequeñas ascuas/polvo estelar flotando hacia arriba
    const particles = Array.from({ length: 120 }, () => ({
      x: Math.random() * width,
      y: Math.random() * height,
      vx: (Math.random() - 0.5) * 0.2,
      vy: -Math.random() * 0.5 - 0.2,
      r: Math.random() * 1.2 + 0.5,
      baseAlpha: Math.random() * 0.5 + 0.1,
      phase: Math.random() * Math.PI * 2,
      speed: Math.random() * 0.02 + 0.01
    }));

    const draw = () => {
      ctx.clearRect(0, 0, width, height);

      // Calcular suavizado del ratón
      mouse.x += (mouse.targetX - mouse.x) * 0.06;
      mouse.y += (mouse.targetY - mouse.y) * 0.06;

      // Dibujar Nebulosa de fondo
      orbs.forEach(orb => {
        orb.x += orb.vx;
        orb.y += orb.vy;
        
        // Rebote en los bordes para que nunca se salgan
        if (orb.x < -orb.r || orb.x > width + orb.r) orb.vx *= -1;
        if (orb.y < -orb.r || orb.y > height + orb.r) orb.vy *= -1;

        const grad = ctx.createRadialGradient(orb.x, orb.y, 0, orb.x, orb.y, orb.r);
        grad.addColorStop(0, orb.color);
        grad.addColorStop(1, 'rgba(0, 0, 0, 0)');
        ctx.fillStyle = grad;
        ctx.beginPath();
        ctx.arc(orb.x, orb.y, orb.r, 0, Math.PI * 2);
        ctx.fill();
      });

      // Dibujar Linterna del Ratón
      const mouseGrad = ctx.createRadialGradient(mouse.x, mouse.y, 0, mouse.x, mouse.y, 350);
      mouseGrad.addColorStop(0, 'rgba(232, 58, 58, 0.12)');
      mouseGrad.addColorStop(1, 'rgba(0, 0, 0, 0)');
      ctx.fillStyle = mouseGrad;
      ctx.beginPath();
      ctx.arc(mouse.x, mouse.y, 350, 0, Math.PI * 2);
      ctx.fill();

      // Dibujar Ascuas Flotantes
      particles.forEach(p => {
        p.x += p.vx;
        p.y += p.vy;
        p.phase += p.speed;
        
        // Movimiento orgánico en "S"
        p.x += Math.cos(p.phase) * 0.3;

        // Si suben del todo, reaparecen abajo
        if (p.y < -10) {
          p.y = height + 10;
          p.x = Math.random() * width;
        }
        if (p.x < -10) p.x = width + 10;
        if (p.x > width + 10) p.x = -10;

        // Parpadeo suave
        const alpha = p.baseAlpha + Math.sin(p.phase) * 0.3;
        const finalAlpha = Math.max(0, Math.min(1, alpha));

        const dx = mouse.x - p.x;
        const dy = mouse.y - p.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        
        // Color base (blanco/gris suave)
        ctx.fillStyle = `rgba(255, 255, 255, ${finalAlpha * 0.5})`;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        ctx.fill();

        // Efecto MAGIA: Se encienden intensamente en rojo si la linterna pasa cerca
        if (dist < 200) {
          const intensity = (1 - dist / 200);
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.r * 2.5, 0, Math.PI * 2);
          ctx.fillStyle = `rgba(232, 58, 58, ${intensity * 0.9})`;
          ctx.fill();
        }
      });

      animId = requestAnimationFrame(draw);
    };

    draw();

    return () => {
      cancelAnimationFrame(animId);
      ro.disconnect();
      if (canvas.parentElement) {
        canvas.parentElement.removeEventListener('mousemove', onMove);
      }
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      style={{
        position: 'absolute',
        inset: 0,
        width: '100%',
        height: '100%',
        zIndex: 0,
        pointerEvents: 'none', /* IMPORTANTÍSIMO: Deja pasar el ratón a los botones de debajo */
      }}
    />
  );
}
